from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest

app = Flask(__name__)

REQUEST_COUNT = Counter('request_count', 'Total Request Count', ['method', 'endpoint', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Request latency', ['method', 'endpoint', 'user_id', 'api_key'])

@app.route('/metrics')
def metrics():
    return generate_latest(), 200

def record_metrics(method, endpoint, user_id, api_key, duration):
    REQUEST_COUNT.labels(method=method, endpoint=endpoint, user_id=user_id, api_key=api_key).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint, user_id=user_id, api_key=api_key).observe(duration)

@app.before_request
def start_timer():
    request.start_time = request.environ.get('werkzeug.request').start_time

@app.after_request
def log_metrics(response):
    if request.path != '/metrics':
        duration = request.elapsed.total_seconds()
        user_id = request.headers.get('X-User-ID', 'unknown')
        api_key = request.headers.get('X-API-Key', 'unknown')
        record_metrics(request.method, request.path, user_id, api_key, duration)
    return response

@app.route('/api', methods=['POST'])
def api():
    data = request.get_json()
    return jsonify({'message': 'Data received', 'data': data}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)